const items = $input.all();
const results = [];

for (const inputItem of items) {
  const data = inputItem.json;

  let sysOID = '';
  if (data.result && data.result.length > 0) {
    sysOID = data.result[0].lastvalue || '';
  }

  if (!sysOID || sysOID.trim() === '') {
    console.log(`❌ Pas d'OID pour hostid: ${data.result?.[0]?.hosts?.[0]?.hostid || 'unknown'}`);
    continue;
  }

  let cleanOID = sysOID.trim().toLowerCase();

  // Convertir format SNMPv2-SMI::enterprises.X en 1.3.6.1.4.1.X
  if (cleanOID.startsWith('snmpv2-smi::enterprises.')) {
    cleanOID = cleanOID.replace('snmpv2-smi::enterprises.', '1.3.6.1.4.1.');
  }

  const hostName = data.result[0].hosts[0].host;
  const hostId = data.result[0].hosts[0].hostid;

  // ===== TABLE DE MAPPING OID → TEMPLATE =====
  // Remplacer les templateId par les IDs réels de votre instance Zabbix
  const oidMappings = [
    // Fortinet - Modèles spécifiques
    { pattern: /1\.3\.6\.1\.4\.1\.12356\.101\.1\.441/, templateId: 'YOUR_TEMPLATE_ID_FORTINET', vendor: 'Fortinet FG-60E/80E' },
    { pattern: /1\.3\.6\.1\.4\.1\.12356\.101\.1\.644/, templateId: 'YOUR_TEMPLATE_ID_FORTINET', vendor: 'Fortinet FG-100F' },
    { pattern: /1\.3\.6\.1\.4\.1\.12356\.101\.1\.845/, templateId: 'YOUR_TEMPLATE_ID_FORTINET', vendor: 'Fortinet FG-200E' },
    { pattern: /1\.3\.6\.1\.4\.1\.12356\.101\.1\.1000/, templateId: 'YOUR_TEMPLATE_ID_FORTINET', vendor: 'Fortinet FG-400F' },
    // Fortinet - Générique (fallback)
    { pattern: /1\.3\.6\.1\.4\.1\.12356/, templateId: 'YOUR_TEMPLATE_ID_FORTINET', vendor: 'Fortinet (generic)' },
    // Dell iDRAC
    { pattern: /1\.3\.6\.1\.4\.1\.674\.10892\.5/, templateId: 'YOUR_TEMPLATE_ID_DELL', vendor: 'Dell iDRAC' },
    // Extreme Networks VSP
    { pattern: /1\.3\.6\.1\.4\.1\.1916\.2\.14/, templateId: 'YOUR_TEMPLATE_ID_EXTREME_VSP', vendor: 'Extreme VSP' },
    // ADVA Optical
    { pattern: /1\.3\.6\.1\.4\.1\.2544\.1\.11\.1\.1/, templateId: 'YOUR_TEMPLATE_ID_ADVA', vendor: 'Adva Optical' },
    // Extreme FabricEngine
    { pattern: /1\.3\.6\.1\.4\.1\.1916\.2\.306/, templateId: 'YOUR_TEMPLATE_ID_EXTREME_FE', vendor: 'Extreme FabricEngine' },
    // Linux Net-SNMP
    { pattern: /1\.3\.6\.1\.4\.1\.8072\.3\.2\.10/, templateId: 'YOUR_TEMPLATE_ID_LINUX', vendor: 'Linux (Net-SNMP)' },
    // Windows Server
    { pattern: /1\.3\.6\.1\.4\.1\.311\.1\.1\.3/, templateId: 'YOUR_TEMPLATE_ID_WINDOWS', vendor: 'Windows Server' },
    // Cisco
    { pattern: /1\.3\.6\.1\.4\.1\.9\.1\./, templateId: 'YOUR_TEMPLATE_ID_CISCO', vendor: 'Cisco' },
    // HP/Aruba
    { pattern: /1\.3\.6\.1\.4\.1\.11\./, templateId: 'YOUR_TEMPLATE_ID_HP', vendor: 'HP/Aruba' },
    // Ubiquiti AP
    { pattern: /1\.3\.6\.1\.4\.1\.41112/, templateId: 'YOUR_TEMPLATE_ID_UBIQUITI', vendor: 'Ubiquiti AP' },
    // Juniper MX
    { pattern: /1\.3\.6\.1\.4\.1\.2636\.1\.1\.1\.2/, templateId: 'YOUR_TEMPLATE_ID_JUNIPER_MX', vendor: 'Juniper MX' },
    // Juniper EX
    { pattern: /1\.3\.6\.1\.4\.1\.2636\.1\.1\.1\.3/, templateId: 'YOUR_TEMPLATE_ID_JUNIPER_EX', vendor: 'Juniper EX' }
    // 🆕 AJOUTEZ VOS OID ICI AU FUR ET À MESURE
  ];

  let matched = false;
  for (const mapping of oidMappings) {
    if (mapping.pattern.test(cleanOID)) {
      console.log(`✅ Match OID: ${hostName} → ${mapping.vendor} (${cleanOID})`);
      results.push({
        json: {
          hostName: hostName,
          hostIdToUpdate: hostId,
          newTemplateId: mapping.templateId,
          baseTemplateId: 'YOUR_DEFAULT_TEMPLATE_ID',
          detectedVendor: mapping.vendor,
          detectedOID: sysOID,
          detectionMethod: 'OID'
        }
      });
      matched = true;
      break;
    }
  }

  if (!matched) {
    console.log(`⚠️ OID non reconnu: ${hostName} - ${cleanOID}`);
  }
}

return results;
